INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05700', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '瞭解人類差異的原因與方式，是服務多元文化背景案主社會工作實務的基礎。學者認為文化能力是一個', '["具備文化能力", "文化無能", "精通文化能力", "文化摧毀  ⑤文化盲目  ⑥培養文化能力。請選出此六個階段由最低層次排到最高層次的正確順序："]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05701', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者與案主之間的專業關係是個案工作的基礎，藉由專業關係的建立可讓助人的過程產生信賴關 係，下列有關形成社會工作專業關係的基本要素，何者錯誤？', '["承諾與責任（commitment and responsibility）", "優勢與價值（strength and value）", "目的（purpose）", "權威與權力（authority and power）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05702', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關個案管理的特性之敘述，何者錯誤？', '["就目標而言：在於改善案主對支持和服務的使用，並發展社會網絡和服務的能力，以增進案主的福祉， 並提升服務的效率和效能", "就組織的回應而言：需要單一組織的回應，連結實務層次的活動、廣泛的資源以及機構層次的活動", "就功能而言：個案管理是統合和聯繫照顧服務的一種機制，並針對評量後的需求提出一套全面性的反應", "就服務對象而言：個案管理是一種以同時遭遇多重問題的個人或家庭；抑或是需長期照顧的個人為對 象的人群服務方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05703', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '同理心是社會工作專業一項重要的能力，同理的溝通不只是深層的了解，還要有同理的回應。「回應者 的語言與非語言表達是在傳遞一種對案主了解的訊息，精確的反映案主事實訊息的部分，以及表相的感 受」是屬於那一個層次的同理回應？', '["低層次的同理回應", "中度的同理回應", "中高層次的同理回應", "高層次的同理回應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05704', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在個案管理介入計畫的執行中，「一種情感、認知和/或行為層次上的協助，透過一種與個人、家庭或團 體的專業關係的方法，使得他們更能夠認知、處理和解決目前的困難」，是下列那一種專業關係方法的 定義？', '["危機諮商", "權能激發", "治療性介入", "家族治療"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05705', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關老人失智症的敘述，何者錯誤？', '["失智症是通盤的智力喪失，包括記憶力、判斷力、抽象思考等功能", "阿茲海默氏症的診斷一般靠的是「排除法」，也就是排除其他疾病及其他類型的失智症（例如血管型 失智、腦傷等）之後的結果", "根據研究臺灣六十五歲以上人口失智症盛行率為0.1%至0.4%，並隨著人口老化而持續增加", "學者稱失智症為「世紀大絕症」，因為它是所有惡疾之最，不但患者深受其害，其家庭成員與親友也 感到十分痛苦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05706', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '104年6月臺灣通過長期照顧服務法，其中說明對於家庭照顧者支持服務之提供，下列那一項服務沒有包 括在內？', '["長照知識、技能訓練", "家庭照顧者的評估與需求了解", "情緒支持及團體服務之轉介", "有關資訊之提供及轉介"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05707', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在個案管理的介入計畫必須要以評量的訊息和所設定的目標為基礎，且介入計畫要能讓案主參與和尊重 案主的意願，並使其成為介入的目標。在設計介入計畫可能會遭遇的問題很多，其中不包括下列那一項？', '["案主有明顯不切實際的目標", "個案/照顧經理對案主有明顯不切實際的期待", "案主與個案/照顧經理對目標的歧見", "專業團隊抗拒參與計畫的過程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05708', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '任務中心取向的工作模式主要知識體系在於認識問題的意義，確認要解決的問題，並將之轉化成為案主 可以瞭解和採取行動之任務，以及有那些問題處置工作階段和技術。依此瞭解任務中心取向之基本假設， 下列何者錯誤？', '["人有改變動力，但只想減輕困難到可忍受為止，而非根本改變", "人之所以有問題是能力暫時受到限制，而非病理因素所致", "解決問題之障礙來自個人認知或動機不足", "人陷入問題困境時就產生改變之動力，因人有適應問題之本能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05709', 'social-worker', 'social-worker-moex-105-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '結案在社會工作專業服務上是一件不容易的事，結案應建立在客觀評估的基礎上，為顧及評估的全面性 效果，結案評估必須將下列指標納入，下列何者錯誤？', '["服務提供的目標是否達成", "服務提供者的績效是否提高", "服務是否符合使用者的需求", "服務使用者對整個結果是否滿意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "9647ec1848e6", "answer_pdf_sha1": "604a6a43c4fe", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
